import { useEffect, useRef, useState } from 'react';
import Editor, { type Monaco } from '@monaco-editor/react';

interface EditorProps {
    value: string;
    onChange: (value: string) => void;
    onCursorChange?: (line: number) => void;
    wasm?: { highlight_scene?: (input: string) => unknown } | null;
}

export function SceneEditor({ value, onChange, onCursorChange, wasm }: EditorProps) {
    const editorRef = useRef<Parameters<NonNullable<Parameters<typeof Editor>[0]['onMount']>>[0] | null>(null);
    const monacoRef = useRef<Monaco | null>(null);
    const [isReady, setIsReady] = useState(false);

    const initLanguage = (monaco: Monaco, highlightFn: (input: string) => unknown) => {
        const languageId = 'webgal';

        if (monaco.languages.getLanguages().some((lang: { id: string }) => lang.id === languageId)) {
            return;
        }

        monaco.languages.register({
            id: languageId,
            extensions: ['.txt'],
            aliases: ['WebGAL', 'WebGAL Script'],
            mimetypes: ['application/webgalscript'],
        });

        monaco.languages.setLanguageConfiguration(languageId, {
            comments: { lineComment: ';' },
            brackets: [
                ['{', '}'],
                ['[', ']'],
                ['(', ')'],
            ],
            autoClosingPairs: [
                { open: '{', close: '}' },
                { open: '[', close: ']' },
                { open: '(', close: ')' },
            ],
        });

        const legend = {
            tokenTypes: [
                'variable',
                'property',
                'enumMember',
                'function',
                'comment',
                'string',
                'number',
                'regexp',
                'operator',
            ],
            tokenModifiers: [],
        };

        monaco.languages.registerDocumentSemanticTokensProvider(languageId, {
            getLegend: () => legend,
            provideDocumentSemanticTokens(model: { getValue(): string }) {
                try {
                    const result = (highlightFn as (input: string) => Array<{
                        deltaLine: number;
                        deltaStart: number;
                        length: number;
                        tokenType: number;
                        tokenModifiersBitset: number;
                    }>)(model.getValue());

                    if (!Array.isArray(result) || result.length === 0) {
                        return { data: new Uint32Array(), resultId: null };
                    }

                    const data = new Uint32Array(result.length * 5);
                    for (let i = 0; i < result.length; i++) {
                        const token = result[i];
                        const offset = i * 5;
                        data[offset] = token.deltaLine;
                        data[offset + 1] = token.deltaStart;
                        data[offset + 2] = token.length;
                        data[offset + 3] = token.tokenType;
                        data[offset + 4] = token.tokenModifiersBitset || 0;
                    }

                    return { data, resultId: null };
                } catch (e) {
                    console.error('Highlight error:', e);
                    return { data: new Uint32Array(), resultId: null };
                }
            },
            releaseDocumentSemanticTokens() {
                // no-op
            },
        });
    };

    const handleMount = (editor: Parameters<NonNullable<Parameters<typeof Editor>[0]['onMount']>>[0], monaco: Monaco) => {
        editorRef.current = editor;
        monacoRef.current = monaco;
        monaco.editor.setTheme('vs-dark');
        setIsReady(true);

        if (wasm?.highlight_scene) {
            initLanguage(monaco, wasm.highlight_scene);
        }

        const model = editor.getModel();
        if (model) {
            monaco.editor.setModelLanguage(model, 'webgal');
        }
    };

    useEffect(() => {
        if (!editorRef.current) {
            return;
        }

        const disposable = editorRef.current.onDidChangeCursorPosition((event) => {
            onCursorChange?.(event.position.lineNumber - 1);
        });

        return () => disposable.dispose();
    }, [onCursorChange]);

    useEffect(() => {
        if (!wasm?.highlight_scene || !monacoRef.current || !isReady) {
            return;
        }
        const alreadyRegistered = monacoRef.current.languages
            .getLanguages()
            .some((lang: { id: string }) => lang.id === 'webgal');
        if (!alreadyRegistered) {
            initLanguage(monacoRef.current, wasm.highlight_scene);
        }

        const editor = editorRef.current;
        if (editor) {
            const model = editor.getModel();
            if (model) {
                // 强制刷新语义高亮
                monacoRef.current.editor.setModelLanguage(model, 'plaintext');
                monacoRef.current.editor.setModelLanguage(model, 'webgal');
                (editor as any).updateOptions({ 'semanticHighlighting.enabled': true });
            }
        }
    }, [wasm, isReady]);

    return (
        <Editor
            height="100%"
            language="webgal"
            theme="vs-dark"
            value={value}
            onChange={(nextValue) => onChange(nextValue ?? '')}
            onMount={handleMount}
            options={{
                minimap: { enabled: false },
                automaticLayout: true,
                fontSize: 14,
                wordWrap: 'on',
                'semanticHighlighting.enabled': true,
            }}
        />
    );
}
